{"path": "/tmp/sv-0074e61017884e34965f0e4ba64cbaa1/Components/Catalog/ProductCard.razor", "file_text": "<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top placeholder-image d-flex align-items-center justify-content-center bg-light"
         style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1 star-rating">@GetStarRating()</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private string GetStarRating()
    {
        int filled = (int)Math.Round(Product.Rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}
"}

